fn cut(py: Python, buf: &[u8]) -> PyResult<(Vec<Py<PyBytes>>, Py<PyBytes>)> {
    let mut i = 0usize;
    let mut out = Vec::new();
    while i + 4 <= buf.len() {
        let n = u32::from_le_bytes([buf[i], buf[i+1], buf[i+2], buf[i+3]]) as usize;
        if n == 0 {
            return Err(PyValueError::new_err("zero frame"));
