        if i + 4 + n > buf.len() {
            break;
        }
        out.push(PyBytes::new(py, &buf[i+4..i+4+n]).into());
        i += 4 + n;
    }
    Ok((out, PyBytes::new(py, &buf[i..]).into()))
}
