def factorize(pq: int) -> tuple[int, int]:
    if pq % 2 == 0:
        return 2, pq // 2
    for c in range(1, 100):
        x = y = secrets.randbelow(pq - 2) + 2
        d = 1
        while d == 1:
            x = (x * x + c) % pq
            y = (y * y + c) % pq
            y = (y * y + c) % pq
            d = gcd(abs(x - y), pq)
        if d != pq:
            return (min(d, pq // d), max(d, pq // d))
    raise ValueError('cant factorize pq')
